define void @test_bigalloc(ptr %dst) {
  %1 = alloca i8, i864 -4294967296, align 1
  store ptr %1, ptr %dst, align 8
  ret void
}

define void @test_negalloc(ptr %dst) {
  %1 = alloca i32, i32 -1, align 4
  store ptr %1, ptr %dst, align 8
  ret void
}
